function generateDynamicResponse(query) {
  const q = query.toLowerCase();
  
  // Helper function to get random items from array
  const getRandomItems = (arr, count = 2) => {
    const shuffled = [...arr].sort(() => 0.5 - Math.random());
    return shuffled.slice(0, count);
  };

  // Introduction variations
  if (q.includes("who") || q.includes("name") || q.includes("about")) {
    const specs = getRandomItems(knowledge.basic.specialization);
    return `I'm ${knowledge.basic.name}, a ${knowledge.basic.year} ${knowledge.basic.role} at ${knowledge.basic.university}. I specialize in ${specs.join(" and ")} engineering.`;
  }

  // Skills variations
  if (q.includes("skill") || q.includes("know") || q.includes("expert")) {
    const techs = getRandomItems(knowledge.skills.technical, 3);
    const domain = getRandomItems(knowledge.skills.domains, 1)[0];
    return `I'm proficient in ${techs.join(", ")}, with particular expertise in ${domain}. I regularly use tools like ${getRandomItems(knowledge.skills.software, 2).join(" and ")}.`;
  }

  // Experience variations
  if (q.includes("experience") || q.includes("work") || q.includes("job")) {
    const randomExp = knowledge.experience[Math.floor(Math.random() * knowledge.experience.length)];
    return `One of my key roles was ${randomExp.role} at ${randomExp.company}, where I ${getRandomItems(randomExp.achievements).join(" and ")}. This is just one example of my professional experience.`;
  }

  // Project variations
  if (q.includes("project") || q.includes("portfolio")) {
    const randomProjects = getRandomItems(knowledge.projects, 2);
    return `I've worked on various exciting projects. For example, ${randomProjects[0].name} focused on ${randomProjects[0].description}, and ${randomProjects[1].name} where I developed ${randomProjects[1].description}.`;
  }

  // Contact variations
  if (q.includes("contact") || q.includes("reach") || q.includes("email") || q.includes("phone")) {
    return `You can reach me at ${knowledge.contact.email} or ${knowledge.contact.phone}. I'm based in ${knowledge.contact.location}, and I'm also active on various social media platforms.`;
  }

  // Education variations
  if (q.includes("study") || q.includes("education") || q.includes("degree") || q.includes("university")) {
    const focuses = getRandomItems(knowledge.education.focus);
    return `I'm pursuing ${knowledge.education.degree} at ${knowledge.education.institution} (${knowledge.education.period}), focusing on ${focuses.join(" and ")}.`;
  }

  // Default response variations
  const suggestions = [
    "You can ask about my education, skills, experience, projects, or how to contact me.",
    "Feel free to ask about my engineering background, technical skills, or ongoing projects.",
    "I can tell you about my work in civil engineering, my education, or my specializations.",
    "Ask me about my experience in hydropower, road design, or structural analysis!"
  ];
  
  return getRandomItems(suggestions, 1)[0];
}

const ChatBot = () => {
  const [isOpen, setIsOpen] = useState(true);
  const [messages, setMessages] = useState([
    { from: "bot", text: "Hi! I'm Sarita's Assistant. How can I help you today?" }
  ]);
  const [input, setInput] = useState("");
  const [isTyping, setIsTyping] = useState(false);
  const messagesEndRef = useRef(null);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim()) return;
    
    const userMsg = { from: "user", text: input };
    setMessages(msgs => [...msgs, userMsg]);
    setInput("");
    setIsTyping(true);

    // Simulate processing time for more natural interaction
    setTimeout(() => {
      const botMsg = { from: "bot", text: generateDynamicResponse(input) };
      setMessages(msgs => [...msgs, botMsg]);
      setIsTyping(false);
    }, Math.random() * 1000 + 500); // Random delay between 500-1500ms
  };

  const handleKeyDown = (e) => {
    if (e.key === "Enter") handleSend();
  };

  return (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      className='fixed bottom-4 right-4 z-50 md:bottom-8 md:right-8'
    >
      <AnimatePresence>
        {isOpen && (
          <motion.div
            initial={{ opacity: 0, y: 20, scale: 0.95 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, y: 20, scale: 0.95 }}
            className="w-[90vw] md:w-[450px] max-w-full bg-black-200/95 backdrop-blur-sm rounded-xl shadow-lg border border-gray-700 flex flex-col mb-4 mx-2 md:mx-0"
          >
            {/* Header */}
            <div className="bg-[#915EFF] text-white p-3 md:p-4 rounded-t-xl flex justify-between items-center">
              <div className="flex items-center gap-2">
                <FaRobot className="text-lg md:text-xl" />
                <span className="font-bold text-sm md:text-base">Sarita's Assistant</span>
              </div>
              <button
                onClick={() => setIsOpen(false)}
                className="text-white/80 hover:text-white transition-colors"
              >
                <FaTimes />
              </button>
            </div>

            {/* Messages */}
            <div className="flex-1 p-3 md:p-4 overflow-y-auto h-[350px] md:h-[500px] custom-scrollbar">
              {messages.map((msg, idx) => (
                <motion.div
                  key={idx}
                  initial={{ opacity: 0, y: 10 }}
                  animate={{ opacity: 1, y: 0 }}
                  className={`mb-3 flex ${msg.from === "user" ? "justify-end" : "justify-start"}`}
                >
                  <div
                    className={`px-4 py-2 rounded-lg text-sm max-w-[80%] ${
                      msg.from === "user"
                        ? "bg-[#915EFF] text-white rounded-br-none"
                        : "bg-gray-800 text-gray-100 rounded-bl-none"
                    }`}
                  >
                    {msg.text}
                  </div>
                </motion.div>
              ))}
              {isTyping && (
                <motion.div
                  initial={{ opacity: 0 }}
                  animate={{ opacity: 1 }}
                  className="flex items-center gap-2 text-gray-400 text-sm"
                >
                  <FaSpinner className="animate-spin" />
                  <span>Typing...</span>
                </motion.div>
              )}
              <div ref={messagesEndRef} />
            </div>

            {/* Input */}
            <div className="flex border-t border-gray-700 p-2">
              <input
                className="flex-1 bg-black-100 text-white rounded-l-lg px-4 py-2 outline-none"
                type="text"
                value={input}
                onChange={e => setInput(e.target.value)}
                onKeyDown={handleKeyDown}
                placeholder="Ask me anything..."
              />
              <button
                className="bg-[#915EFF] text-white px-4 rounded-r-lg font-bold hover:bg-[#8048ff] transition-colors flex items-center gap-2"
                onClick={handleSend}
              >
                <FaPaperPlane className="text-sm" />
              </button>
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      {/* Toggle Button */}
      {!isOpen && (
        <motion.button
          initial={{ scale: 0 }}
          animate={{ scale: 1 }}
          className="bg-[#915EFF] text-white p-4 rounded-full shadow-lg hover:bg-[#8048ff] transition-colors"
          onClick={() => setIsOpen(true)}
        >
          <FaRobot className="text-xl" />
        </motion.button>
      )}
    </motion.div>
  );
};

export default ChatBot;
